WITH total_count AS (
  SELECT count(*) as total FROM patient
  WHERE sex = 'M'
  UNION ALL
  SELECT count(*) as total from patient where admission not like '+'
  )
SELECT case when s.total != t.total then 100 * abs(s.total - t.total) / greatest(s.total, t.total)
            else 0
         end percent_deviation
FROM   ( SELECT count(*) as total FROM patient where sex = 'M' and admission like '+'
  ) s, ( SELECT count(*) as total from patient where sex = 'M' and admission not like '+'
  ) t;

with total_patients as (
  select count(*) from patient where date_part('year', birthday) between 1930 and 1940
), inpatient_patients as (
  select count(*) from patient
  join examination on patient.id = examination.id
  where admission = '+'
    and date_part('year', birthday) between 1930 and 1940
)
select cast(inpatient_patients.count * 100 / total_patients.count as numeric) || '%' as percentage_of_inpatient_patients
from total_patients, inpatient_patients;

SELECT MAX(age) - MIN(age) AS age_gap FROM (
